const input = $input.first().json;

// Parse input â€” handle both JSON string and object
let action, templateId, category, credKey;
try {
  const parsed = typeof input.query === 'string' ? JSON.parse(input.query) : input;
  action = parsed.action || input.action;
  templateId = parsed.id || input.id;
  category = parsed.category || input.category;
  credKey = parsed.cred_key || input.cred_key;
} catch(e) {
  action = input.action;
  templateId = input.id;
  category = input.category;
  credKey = input.cred_key;
}

const CDN_BASE = 'https://cdn.jsdelivr.net/gh/freddy-schuetz/n8n-claw-templates@e71b434/templates';
const N8N_API = '{{N8N_INTERNAL_URL}}/api/v1';
const N8N_KEY = '{{N8N_API_KEY}}';
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const N8N_PUBLIC_URL = '{{N8N_URL}}';
const CREDENTIAL_FORM_PATH = '{{CREDENTIAL_FORM_WEBHOOK_ID}}';

const apiHeaders = { 'X-N8N-API-KEY': N8N_KEY, 'Content-Type': 'application/json' };
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' };

// Helper: update agent config with current MCP registry
async function updateAgentConfig() {
  try {
    const servers = await helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/mcp_registry?select=server_name,path,mcp_url,description,tools&active=eq.true&order=created_at.asc',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });

    if (!servers || !servers.length) return;

    const lines = servers.map(s => {
      const tools = Array.isArray(s.tools) ? s.tools.join(', ') : (s.tools || '?');
      return '- ' + s.server_name + ': ' + s.mcp_url + ' (Tool: ' + tools + ') â€” ' + (s.description || '');
    });

    const instructions = 'You have MCP Skills \u2014 installable capabilities powered by the Model Context Protocol (MCP):\n\n'
      + '## MCP Client (mcp_client tool)\n'
      + 'Call tools on MCP skill servers. Parameters:\n'
      + '- mcp_url: Server URL\n'
      + '- tool_name: Name of the tool\n'
      + '- arguments: JSON object with tool parameters\n\n'
      + '## Skills Library (library_manager tool)\n'
      + 'Install/remove pre-built skills from the catalog.\n'
      + 'Actions: list_templates, install_template, remove_template, add_credential\n'
      + 'When the user asks about available skills, ALWAYS use this tool with list_templates.\n\n'
      + '## MCP Builder (mcp_builder tool)\n'
      + 'Build custom skills from scratch for APIs not in the catalog.\n'
      + '- task: What the skill should do\n'
      + 'NOTE: After build, deactivate + reactivate once in n8n UI (webhook bug).\n\n'
      + '## Currently installed MCP Skills (' + servers.length + ' total):\n'
      + lines.join('\n') + '\n\n'
      + '## Registry\n'
      + 'All active skills: SELECT * FROM mcp_registry WHERE active = true;';

    await helpers.httpRequest({
      method: 'PATCH',
      url: SUPABASE_URL + '/rest/v1/agents?key=eq.mcp_instructions',
      headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ content: instructions })
    });
  } catch(e) {
    // Non-critical â€” don't fail the whole operation
  }
}

// â”€â”€ ACTION: list_templates â”€â”€
if (action === 'list_templates') {
  const index = await helpers.httpRequest({
    method: 'GET',
    url: CDN_BASE + '/index.json',
    headers: { 'Accept': 'application/json' }
  });

  let templates = index.templates || [];
  if (category) {
    templates = templates.filter(t => t.category === category);
  }

  // Cross-reference with mcp_registry for installed status
  try {
    const installed = await helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/mcp_registry?select=template_id&template_id=not.is.null',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
    const installedIds = new Set((installed || []).map(r => r.template_id));
    templates = templates.map(t => ({ ...t, installed: installedIds.has(t.id) }));
  } catch(e) {
    // If registry check fails, just show templates without installed status
  }

  return [{ json: { templates, total: templates.length } }];

// â”€â”€ ACTION: install_template â”€â”€
} else if (action === 'install_template') {
  if (!templateId) {
    return [{ json: { error: 'Parameter "id" is missing. Example: {"action":"install_template","id":"weather-openmeteo"}' } }];
  }

  // Check if already installed
  try {
    const existing = await helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/mcp_registry?template_id=eq.' + templateId + '&select=id',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
    if (existing && existing.length > 0) {
      return [{ json: { error: 'Template "' + templateId + '" is already installed.' } }];
    }
  } catch(e) { /* proceed */ }

  // Fetch manifest
  let manifest;
  try {
    manifest = await helpers.httpRequest({
      method: 'GET',
      url: CDN_BASE + '/' + templateId + '/manifest.json',
      headers: { 'Accept': 'application/json' }
    });
  } catch(e) {
    return [{ json: { error: 'Template "' + templateId + '" not found in catalog.' } }];
  }

  if (manifest.type === 'bridge') {
    return [{ json: { error: 'Bridge templates are not yet supported in Phase 1.' } }];
  }

  // Fetch workflow bundle
  let bundle;
  try {
    bundle = await helpers.httpRequest({
      method: 'GET',
      url: CDN_BASE + '/' + templateId + '/workflow.json',
      headers: { 'Accept': 'application/json' }
    });
  } catch(e) {
    return [{ json: { error: 'workflow.json for "' + templateId + '" could not be loaded: ' + e.message } }];
  }

  if (bundle.format !== 'n8n-claw-template') {
    return [{ json: { error: 'Unknown template format: ' + (bundle.format || 'none') } }];
  }

  // 1. Import sub-workflow
  let subId;
  try {
    let subJson = JSON.stringify(bundle.sub);
    subJson = subJson.replace(/\{\{SUPABASE_URL\}\}/g, SUPABASE_URL);
    subJson = subJson.replace(/\{\{SUPABASE_SERVICE_KEY\}\}/g, SUPABASE_KEY);
    const subResult = await helpers.httpRequest({
      method: 'POST',
      url: N8N_API + '/workflows',
      headers: apiHeaders,
      body: subJson
    });
    subId = subResult.id;
  } catch(e) {
    return [{ json: { error: 'Sub-workflow import failed: ' + e.message } }];
  }

  // 2. Activate sub-workflow
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: N8N_API + '/workflows/' + subId + '/activate',
      headers: apiHeaders
    });
  } catch(e) {
    // Non-critical for sub-workflows without triggers
  }

  // 3. Patch server workflow with sub-workflow ID and import
  let serverWorkflowId;
  try {
    let serverJson = JSON.stringify(bundle.server).replace(/REPLACE_SUB_WORKFLOW_ID/g, subId);
    serverJson = serverJson.replace(/\{\{SUPABASE_URL\}\}/g, SUPABASE_URL);
    serverJson = serverJson.replace(/\{\{SUPABASE_SERVICE_KEY\}\}/g, SUPABASE_KEY);
    const serverResult = await helpers.httpRequest({
      method: 'POST',
      url: N8N_API + '/workflows',
      headers: apiHeaders,
      body: serverJson
    });
    serverWorkflowId = serverResult.id;
  } catch(e) {
    // Rollback: delete sub-workflow
    try {
      await helpers.httpRequest({ method: 'DELETE', url: N8N_API + '/workflows/' + subId, headers: apiHeaders });
    } catch(e2) { /* best effort */ }
    return [{ json: { error: 'MCP server workflow import failed: ' + e.message } }];
  }

  // 4. Activate server workflow
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: N8N_API + '/workflows/' + serverWorkflowId + '/activate',
      headers: apiHeaders
    });
  } catch(e) {
    // Expected to partially fail (webhook bug) â€” user must toggle in UI
  }

  // 5. Get MCP path and tool names from bundle
  const mcpTriggerNode = bundle.server.nodes.find(n => n.type && n.type.includes('mcpTrigger'));
  const mcpPath = mcpTriggerNode ? mcpTriggerNode.parameters.path : templateId;
  const toolNames = (manifest.tools || []).map(t => t.name);

  // 6. Register in mcp_registry
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/mcp_registry',
      headers: { ...pgHeaders, 'Prefer': 'return=representation' },
      body: JSON.stringify({
        server_name: manifest.name,
        path: mcpPath,
        mcp_url: N8N_PUBLIC_URL + '/mcp/' + mcpPath,
        description: manifest.description,
        tools: toolNames,
        workflow_id: serverWorkflowId,
        sub_workflow_id: subId,
        active: true,
        template_id: templateId,
        template_type: manifest.type
      })
    });
  } catch(e) {
    return [{ json: {
      success: true,
      warning: 'Workflow imported, but registry entry failed: ' + e.message,
      workflow_id: serverWorkflowId,
      sub_workflow_id: subId,
      template_id: templateId
    } }];
  }

  // 7. Update agent config
  await updateAgentConfig();

  const needsCreds = manifest.credentials_required && manifest.credentials_required.length > 0;
  let credLinks = [];

  if (needsCreds) {
    for (const cred of manifest.credentials_required) {
      try {
        const tokenResult = await helpers.httpRequest({
          method: 'POST',
          url: SUPABASE_URL + '/rest/v1/credential_tokens',
          headers: { ...pgHeaders, 'Prefer': 'return=representation' },
          body: JSON.stringify({
            template_id: templateId,
            cred_key: cred.key,
            cred_label: cred.label || cred.key,
            cred_hint: cred.hint || ''
          })
        });
        const token = tokenResult[0].token;
        credLinks.push({
          label: cred.label || cred.key,
          hint: cred.hint || '',
          url: N8N_PUBLIC_URL + '/form/' + CREDENTIAL_FORM_PATH + '?token=' + token
        });
      } catch(e) {
        credLinks.push({ label: cred.key, error: e.message });
      }
    }
  }

  let msg = 'Template "' + templateId + '" successfully installed.';
  msg += '\nMCP Server Workflow: ' + serverWorkflowId;
  msg += '\nMCP Path: /mcp/' + mcpPath;
  msg += '\n\nPlease deactivate + reactivate once in n8n UI (webhook bug).';

  if (credLinks.length > 0) {
    msg += '\n\nThis template requires API credentials:';
    for (const link of credLinks) {
      if (link.error) {
        msg += '\n- ' + link.label + ': Token generation failed.';
      } else {
        msg += '\n- ' + link.label + ': ' + link.url + ' (valid 10 min)';
        if (link.hint) msg += '\n  Hint: ' + link.hint;
      }
    }
  }

  return [{ json: {
    success: true,
    workflow_id: serverWorkflowId,
    sub_workflow_id: subId,
    template_id: templateId,
    mcp_path: mcpPath,
    message: msg
  } }];

// â”€â”€ ACTION: remove_template â”€â”€
} else if (action === 'remove_template') {
  if (!templateId) {
    return [{ json: { error: 'Parameter "id" is missing. Example: {"action":"remove_template","id":"weather-openmeteo"}' } }];
  }

  // Find in registry
  let entries;
  try {
    entries = await helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/mcp_registry?template_id=eq.' + templateId + '&select=*',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
  } catch(e) {
    return [{ json: { error: 'Registry query failed: ' + e.message } }];
  }

  if (!entries || entries.length === 0) {
    return [{ json: { error: 'Template "' + templateId + '" not found in the registry.' } }];
  }

  const entry = entries[0];

  // Deactivate workflow
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: N8N_API + '/workflows/' + entry.workflow_id + '/deactivate',
      headers: apiHeaders
    });
  } catch(e) { /* best effort */ }

  // Delete server workflow
  try {
    await helpers.httpRequest({
      method: 'DELETE',
      url: N8N_API + '/workflows/' + entry.workflow_id,
      headers: apiHeaders
    });
  } catch(e) {
    return [{ json: { error: 'Workflow deletion failed: ' + e.message } }];
  }

  // Delete sub-workflow
  if (entry.sub_workflow_id) {
    try {
      await helpers.httpRequest({
        method: 'DELETE',
        url: N8N_API + '/workflows/' + entry.sub_workflow_id,
        headers: apiHeaders
      });
    } catch(e) { /* best effort */ }
  }

  // Remove from registry
  try {
    await helpers.httpRequest({
      method: 'DELETE',
      url: SUPABASE_URL + '/rest/v1/mcp_registry?template_id=eq.' + templateId,
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
  } catch(e) { /* best effort */ }

  // Update agent config
  await updateAgentConfig();

  return [{ json: {
    success: true,
    message: 'Template "' + templateId + '" successfully removed.',
    deleted_workflow_id: entry.workflow_id
  } }];

} else if (action === 'add_credential') {
  if (!templateId) return [{ json: { error: 'Parameter "id" is missing.' } }];

  // Verify template is installed
  const credEntries = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/mcp_registry?template_id=eq.' + templateId + '&select=id',
    headers: pgHeaders
  });
  if (!credEntries || credEntries.length === 0) {
    return [{ json: { error: 'Template "' + templateId + '" is not installed.' } }];
  }

  // Fetch manifest for credential metadata
  let credManifest;
  try {
    credManifest = await helpers.httpRequest({
      method: 'GET',
      url: CDN_BASE + '/' + templateId + '/manifest.json',
      headers: { 'Accept': 'application/json' }
    });
  } catch(e) {
    return [{ json: { error: 'Could not load manifest for "' + templateId + '": ' + e.message } }];
  }

  const allCreds = credManifest.credentials_required || [];
  if (allCreds.length === 0) {
    return [{ json: { error: 'Template "' + templateId + '" does not require any credentials.' } }];
  }

  // If cred_key given, filter to just that one; otherwise generate for all
  const credsToGenerate = credKey ? allCreds.filter(c => c.key === credKey) : allCreds;
  if (credKey && credsToGenerate.length === 0) {
    return [{ json: { error: 'Unknown credential key "' + credKey + '". Available: ' + allCreds.map(c => c.key).join(', ') } }];
  }

  const credLinks = [];
  for (const cred of credsToGenerate) {
    try {
      const tokenResult = await helpers.httpRequest({
        method: 'POST',
        url: SUPABASE_URL + '/rest/v1/credential_tokens',
        headers: { ...pgHeaders, 'Prefer': 'return=representation' },
        body: JSON.stringify({ template_id: templateId, cred_key: cred.key, cred_label: cred.label || cred.key, cred_hint: cred.hint || '' })
      });
      const token = tokenResult[0].token;
      credLinks.push({ label: cred.label || cred.key, hint: cred.hint || '', url: N8N_PUBLIC_URL + '/form/' + CREDENTIAL_FORM_PATH + '?token=' + token });
    } catch(e) {
      credLinks.push({ label: cred.key, error: e.message });
    }
  }

  let credMsg = 'Enter your credentials securely via these links (valid 10 min):';
  for (const link of credLinks) {
    if (link.error) {
      credMsg += '\n- ' + link.label + ': Token generation failed.';
    } else {
      credMsg += '\n- ' + link.label + ': ' + link.url;
      if (link.hint) credMsg += '\n  Hint: ' + link.hint;
    }
  }

  return [{ json: {
    success: true,
    message: credMsg,
    credential_links: credLinks
  } }];

} else {
  return [{ json: {
    error: 'Unknown action: "' + (action || '') + '". Available: list_templates, install_template, remove_template, add_credential',
    examples: [
      '{"action":"list_templates"}',
      '{"action":"install_template","id":"weather-openmeteo"}',
      '{"action":"remove_template","id":"weather-openmeteo"}',
      '{"action":"add_credential","id":"google-reviews"}'
    ]
  } }];
}
